@ SuppressWarnings ( "serial" ) public class ParamTag extends TagSupport { protected String name = null ; protected String mode = null ; protected String map = null ; protected String alias = null ; protected String attribute = null ; protected Object paramValue = null ; public void setName ( String name ) { this . name = name ; } public String getName ( ) { return name ; } public void setMode ( String mode ) { this . mode = mode ; } public String getMode ( ) { return this . mode ; } public void setAttribute ( String attribute ) { this . attribute = attribute ; } public String getAttribute ( ) { return attribute ; } public void setValue ( Object paramValue ) { this . paramValue = paramValue ; } public Object getValue ( ) { return paramValue ; } public void setMap ( String map ) { this . map = map ; } public String getMap ( ) { return map ; } public void setAlias ( String alias ) { this . alias = alias ; } public String getAlias ( ) { return this . alias ; } @ Override public int doStartTag ( ) throws JspTagException { AbstractParameterTag sTag = ( AbstractParameterTag ) findAncestorWithClass ( this , AbstractParameterTag . class ) ; if ( sTag == null ) throw new JspTagException ( "ParamTag not inside a ServiceTag." ) ; if ( mode != null && ! mode . equals ( "IN" ) && ! mode . equals ( "OUT" ) && ! mode . equals ( "INOUT" ) ) throw new JspTagException ( "Invalid mode attribute. Must be IN/OUT/INOUT." ) ; if ( mode != null && ( mode . equals ( "OUT" ) || mode . equals ( "INOUT" ) ) ) sTag . addOutParameter ( name , ( alias != null ? alias : name ) ) ; if ( mode == null || mode . equals ( "IN" ) || mode . equals ( "INOUT" ) ) { Object value = null ; if ( attribute != null ) { if ( map == null ) { value = pageContext . findAttribute ( attribute ) ; if ( value == null ) value = pageContext . getRequest ( ) . getParameter ( attribute ) ; } else { try { Map < String , Object > mapObject = UtilGenerics . cast ( pageContext . findAttribute ( map ) ) ; value = mapObject . get ( attribute ) ; } catch ( Exception e ) { throw new JspTagException ( "Problem processing map (" + map + ") for attributes." ) ; } } } if ( value == null && paramValue != null ) { value = paramValue ; } sTag . addInParameter ( name , value ) ; } return SKIP_BODY ; } @ Override public int doEndTag ( ) { return EVAL_PAGE ; } }